import{_ as d,C as c,o as s,c as u,a2 as i,b as r,w as t,a,E as l,a3 as p,j as n}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"Warp Agentic Loop — Oz Agent Processing","description":"","frontmatter":{"title":"Warp Agentic Loop — Oz Agent Processing","status":"complete"},"headers":[],"relativePath":"research/agents/warp/agentic-loop.md","filePath":"research/agents/warp/agentic-loop.md"}'),g={name:"research/agents/warp/agentic-loop.md"};function h(m,e,b,f,C,v){const o=c("Mermaid");return s(),u("div",null,[e[4]||(e[4]=i('<h1 id="agentic-loop" tabindex="-1">Agentic Loop <a class="header-anchor" href="#agentic-loop" aria-label="Permalink to &quot;Agentic Loop&quot;">​</a></h1><blockquote><p>Warp&#39;s agent operates through the Oz orchestration platform, processing requests via a cycle of planning, command execution, terminal observation, and iterative refinement. The loop is distinguished by Full Terminal Use — the ability to attach to and interact with live interactive processes.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Unlike wrapper-based agents that follow a simple generate-execute-observe loop, Warp&#39;s agent loop is tightly coupled with the terminal&#39;s block system and PTY layer. The agent doesn&#39;t just execute commands — it observes the live terminal state, interacts with running processes, and can be &quot;tagged in&quot; by the user mid-session.</p><h2 id="request-processing-flow" tabindex="-1">Request Processing Flow <a class="header-anchor" href="#request-processing-flow" aria-label="Permalink to &quot;Request Processing Flow&quot;">​</a></h2>',5)),(s(),r(p,null,{default:t(()=>[l(o,{id:"mermaid-17",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22User%20Request%3Cbr%2F%3E(natural%20language%2C%20%40references%2C%20images%2C%20URLs%2C%20block%20selections)%22%5D%20--%3E%20B%7B%22Input%20Classification%22%7D%0A%20%20%20%20B%20--%20%22Simple%20command%22%20--%3E%20T%5B%22Terminal%20View%3Cbr%2F%3E(inline%20execution)%22%5D%0A%20%20%20%20B%20--%20%22Complex%20task%22%20--%3E%20CV%5B%22Conversation%20View%3Cbr%2F%3E(multi-turn%20agent)%22%5D%0A%20%20%20%20B%20--%20%22Ambiguous%22%20--%3E%20AD%5B%22Agent%20decides%20based%20on%20context%22%5D%0A%20%20%20%20CV%20--%3E%20C%5B%22Context%20Assembly%3Cbr%2F%3E1.%20Codebase%20context%20(semantic%20index%20%2F%20embeddings)%3Cbr%2F%3E2.%20Referenced%20blocks%2C%20files%2C%20folders%2C%20symbols%3Cbr%2F%3E3.%20Rules%20(global%20%2B%20project%20AGENTS.md%2C%20hierarchical)%3Cbr%2F%3E4.%20Skills%20(SKILL.md%20files)%3Cbr%2F%3E5.%20Conversation%20history%20(or%20compacted%20summary)%3Cbr%2F%3E6.%20System%20prompt%20with%20permission%20level%22%5D%0A%20%20%20%20C%20--%3E%20P%5B%22Planning%20Phase%3Cbr%2F%3E%2Fplan%3A%20rich%20editor%2C%20version%20history%2C%3Cbr%2F%3Estep-by-step%20breakdown%2C%20selective%20execution%3Cbr%2F%3EAuto-planning%3A%20agent%20proposes%20%E2%86%92%20user%20approves%20%E2%86%92%20execute%22%5D%0A%20%20%20%20P%20--%3E%20SA%5B%22Select%20Action%3Cbr%2F%3E(command%2C%20file%20edit%2C%20web%20search%2C%20MCP%2C%20etc.)%22%5D%0A%20%20%20%20SA%20--%3E%20PC%7B%22Permission%20Check%3Cbr%2F%3E'Ask%20on%20first%20write'%20%2F%20'Always%20ask'%20%2F%20'Always%20allow'%22%7D%0A%20%20%20%20PC%20--%3E%20EX%5B%22Execute%20Action%3Cbr%2F%3E(PTY%20write%2C%20file%20op%2C%20tool%20invocation)%22%5D%0A%20%20%20%20EX%20--%3E%20OB%5B%22Observe%20Result%3Cbr%2F%3E(read%20terminal%20buffer%2C%20check%20exit%20code%2C%20parse%20output)%22%5D%0A%20%20%20%20OB%20--%3E%20ED%7B%22Evaluate%20%26%20Decide%22%7D%0A%20%20%20%20ED%20--%20%22Done%22%20--%3E%20R%5B%22Report%20to%20User%22%5D%0A%20%20%20%20ED%20--%20%22Error%22%20--%3E%20SA%0A%20%20%20%20ED%20--%20%22More%20steps%22%20--%3E%20SA%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=n("h2",{id:"full-terminal-use",tabindex:"-1"},[a("Full Terminal Use "),n("a",{class:"header-anchor",href:"#full-terminal-use","aria-label":'Permalink to "Full Terminal Use"'},"​")],-1)),e[6]||(e[6]=n("p",null,[a("Full Terminal Use (FTU) is Warp's most distinctive agent capability. Because Warp owns the PTY, the agent can interact with "),n("strong",null,"running interactive processes"),a(" — something no wrapper-based agent can do.")],-1)),e[7]||(e[7]=n("h3",{id:"how-ftu-works",tabindex:"-1"},[a("How FTU Works "),n("a",{class:"header-anchor",href:"#how-ftu-works","aria-label":'Permalink to "How FTU Works"'},"​")],-1)),(s(),r(p,null,{default:t(()=>[l(o,{id:"mermaid-27",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20IP%5B%22Interactive%20Process%20(psql%2C%20vim%2C%20python%2C%20gdb%2C%20npm%20run%20dev%2C%20docker%20exec)%22%5D%0A%20%20%20%20%20%20%20%20PTY%5B%22PTY%3Cbr%2F%3E(pseudo%20terminal)%22%5D%20%3C--%3E%20TB%5B%22Terminal%20Buffer%3Cbr%2F%3E(live%20output)%22%5D%20%3C--%3E%20AH%5B%22Agent%20%2F%20Human%3Cbr%2F%3E(read%20buffer%2C%3Cbr%2F%3Ewrite%20input%2C%3Cbr%2F%3Eobserve%20state)%22%5D%0A%20%20%20%20end%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[a(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=i(`<h3 id="ftu-scenarios" tabindex="-1">FTU Scenarios <a class="header-anchor" href="#ftu-scenarios" aria-label="Permalink to &quot;FTU Scenarios&quot;">​</a></h3><p><strong>Scenario 1: Agent starts interactive tool</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User:  &quot;Connect to the production database and check the users table schema&quot;</span></span>
<span class="line"><span>Agent: [Starts psql session]</span></span>
<span class="line"><span>       [Reads terminal buffer showing psql prompt]</span></span>
<span class="line"><span>       [Writes: \\d users]</span></span>
<span class="line"><span>       [Reads schema output]</span></span>
<span class="line"><span>       [Reports findings to user]</span></span>
<span class="line"><span>       [Writes: \\q to exit]</span></span></code></pre></div><p><strong>Scenario 2: User &quot;tags in&quot; agent to running process</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User:  [Is in a Python REPL, encounters complex data transformation]</span></span>
<span class="line"><span>User:  &quot;Hey agent, I need to pivot this DataFrame by date&quot;</span></span>
<span class="line"><span>Agent: [Reads terminal buffer — sees current Python state, variable names]</span></span>
<span class="line"><span>       [Writes Python code to the REPL]</span></span>
<span class="line"><span>       [Reads output to verify correctness]</span></span>
<span class="line"><span>       [Hands back control to user]</span></span></code></pre></div><p><strong>Scenario 3: Agent monitors long-running process</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User:  &quot;Start the dev server and fix any compilation errors&quot;</span></span>
<span class="line"><span>Agent: [Writes: npm run dev]</span></span>
<span class="line"><span>       [Monitors terminal buffer for output]</span></span>
<span class="line"><span>       [Detects compilation error]</span></span>
<span class="line"><span>       [Edits source file to fix error]</span></span>
<span class="line"><span>       [Observes dev server hot-reload success]</span></span>
<span class="line"><span>       [Reports fix to user]</span></span></code></pre></div><h3 id="ftu-capabilities" tabindex="-1">FTU Capabilities <a class="header-anchor" href="#ftu-capabilities" aria-label="Permalink to &quot;FTU Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td><strong>Buffer reading</strong></td><td>Agent reads the live terminal buffer content</td></tr><tr><td><strong>PTY writing</strong></td><td>Agent writes input to the PTY (keystrokes, commands)</td></tr><tr><td><strong>Process detection</strong></td><td>Agent identifies what interactive process is running</td></tr><tr><td><strong>State awareness</strong></td><td>Agent understands prompts, error states, waiting states</td></tr><tr><td><strong>Graceful exit</strong></td><td>Agent can cleanly exit interactive tools when done</td></tr><tr><td><strong>Handback</strong></td><td>Agent returns control to user at natural breakpoints</td></tr></tbody></table><h2 id="takeover-handback-pattern" tabindex="-1">Takeover / Handback Pattern <a class="header-anchor" href="#takeover-handback-pattern" aria-label="Permalink to &quot;Takeover / Handback Pattern&quot;">​</a></h2><p>Warp implements a structured control transfer mechanism between human and agent:</p><h3 id="control-flow" tabindex="-1">Control Flow <a class="header-anchor" href="#control-flow" aria-label="Permalink to &quot;Control Flow&quot;">​</a></h3>`,12)),(s(),r(p,null,{default:t(()=>[l(o,{id:"mermaid-117",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20HC%5B%22Human%20Control%3Cbr%2F%3EUser%20types%20commands%2C%3Cbr%2F%3Einteracts%20with%20tools%22%5D%20--%20%22tag%20in%3Cbr%2F%3E(explicit%20request%3Cbr%2F%3Eor%20error%20detection)%22%20--%3E%20AC%5B%22Agent%20Control%3Cbr%2F%3EAgent%20reads%20buffer%2C%3Cbr%2F%3Ewrites%20PTY%2C%3Cbr%2F%3Eexecutes%20plan%22%5D%0A%20%20%20%20AC%20--%20%22handback%3Cbr%2F%3E(task%20done%2C%3Cbr%2F%3Eneeds%20input%2C%3Cbr%2F%3Epermission%20denied)%22%20--%3E%20HC%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[a(" Loading... ",-1)])]),_:1})),e[9]||(e[9]=i(`<h3 id="takeover-triggers" tabindex="-1">Takeover Triggers <a class="header-anchor" href="#takeover-triggers" aria-label="Permalink to &quot;Takeover Triggers&quot;">​</a></h3><ul><li><strong>Explicit request</strong>: User asks agent to take over (e.g., &quot;fix this for me&quot;)</li><li><strong>Error detection</strong>: Active AI detects command failure and offers to help</li><li><strong>Proactive suggestion</strong>: Agent notices pattern and suggests intervention</li><li><strong>Tag-in gesture</strong>: User invokes agent while in an interactive tool</li></ul><h3 id="handback-triggers" tabindex="-1">Handback Triggers <a class="header-anchor" href="#handback-triggers" aria-label="Permalink to &quot;Handback Triggers&quot;">​</a></h3><ul><li><strong>Task completion</strong>: Agent finished executing its plan</li><li><strong>Permission boundary</strong>: Agent needs write permission it doesn&#39;t have</li><li><strong>Human judgment needed</strong>: Agent encounters ambiguous situation</li><li><strong>Interactive input required</strong>: Process needs human-specific input (passwords, 2FA)</li><li><strong>Natural breakpoint</strong>: Agent reaches a logical stopping point</li></ul><h2 id="permission-model" tabindex="-1">Permission Model <a class="header-anchor" href="#permission-model" aria-label="Permalink to &quot;Permission Model&quot;">​</a></h2><p>Warp implements three permission levels for agent actions:</p><h3 id="permission-levels" tabindex="-1">Permission Levels <a class="header-anchor" href="#permission-levels" aria-label="Permalink to &quot;Permission Levels&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>Behavior</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Ask on first write</strong></td><td>Agent executes read-only actions freely; prompts on first destructive action per category</td><td>Default for most users</td></tr><tr><td><strong>Always ask</strong></td><td>Agent prompts for every action</td><td>High-security environments</td></tr><tr><td><strong>Always allow</strong></td><td>Agent executes all actions without prompting</td><td>Trusted automation, CI/CD</td></tr></tbody></table><h3 id="what-counts-as-write-actions" tabindex="-1">What Counts as &quot;Write&quot; Actions <a class="header-anchor" href="#what-counts-as-write-actions" aria-label="Permalink to &quot;What Counts as &quot;Write&quot; Actions&quot;">​</a></h3><ul><li>File creation, modification, deletion</li><li>Shell commands that modify state (git commit, rm, mv, etc.)</li><li>PTY input to interactive processes</li><li>Network requests that modify remote state</li></ul><h3 id="read-only-actions-always-allowed" tabindex="-1">Read-Only Actions (Always Allowed) <a class="header-anchor" href="#read-only-actions-always-allowed" aria-label="Permalink to &quot;Read-Only Actions (Always Allowed)&quot;">​</a></h3><ul><li>Reading file contents</li><li>Listing directories</li><li>Reading terminal buffer</li><li>Semantic index queries</li><li>Web search (information retrieval)</li></ul><h2 id="planning-and-execution" tabindex="-1">Planning and Execution <a class="header-anchor" href="#planning-and-execution" aria-label="Permalink to &quot;Planning and Execution&quot;">​</a></h2><h3 id="the-plan-command" tabindex="-1">The /plan Command <a class="header-anchor" href="#the-plan-command" aria-label="Permalink to &quot;The /plan Command&quot;">​</a></h3><p>Warp provides a dedicated planning workflow via the <code>/plan</code> command:</p><ol><li><strong>Plan creation</strong>: Agent generates a structured plan with numbered steps</li><li><strong>Rich editor</strong>: Plan appears in a rich text editor, not just terminal text</li><li><strong>Version history</strong>: Plans are versioned; user can see evolution of approach</li><li><strong>Selective execution</strong>: User can execute specific steps, skip others</li><li><strong>Plan iteration</strong>: Agent can refine plan based on user feedback before executing</li><li><strong>Persistent storage</strong>: Plans saved to Warp Drive for future reference</li></ol><h3 id="auto-planning" tabindex="-1">Auto-Planning <a class="header-anchor" href="#auto-planning" aria-label="Permalink to &quot;Auto-Planning&quot;">​</a></h3><p>For complex tasks, the agent may automatically propose a plan:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Migrate the authentication system from JWT to session-based auth&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent: I&#39;ll create a plan for this migration:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Plan v1: Auth Migration</span></span>
<span class="line"><span>├── Step 1: Analyze current JWT implementation</span></span>
<span class="line"><span>│   ├── Identify all JWT creation/validation points</span></span>
<span class="line"><span>│   └── Map session management requirements</span></span>
<span class="line"><span>├── Step 2: Create session store</span></span>
<span class="line"><span>│   ├── Add Redis session middleware</span></span>
<span class="line"><span>│   └── Create session model</span></span>
<span class="line"><span>├── Step 3: Replace JWT endpoints</span></span>
<span class="line"><span>│   ├── Update login endpoint</span></span>
<span class="line"><span>│   ├── Update token refresh → session refresh</span></span>
<span class="line"><span>│   └── Update logout to destroy session</span></span>
<span class="line"><span>├── Step 4: Update middleware</span></span>
<span class="line"><span>│   └── Replace JWT validation with session lookup</span></span>
<span class="line"><span>└── Step 5: Test and verify</span></span>
<span class="line"><span>    ├── Run existing auth tests</span></span>
<span class="line"><span>    └── Add session-specific tests</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Execute All] [Execute Step 1] [Edit Plan]</span></span></code></pre></div><h2 id="auto-detection-of-input-type" tabindex="-1">Auto-Detection of Input Type <a class="header-anchor" href="#auto-detection-of-input-type" aria-label="Permalink to &quot;Auto-Detection of Input Type&quot;">​</a></h2><p>Warp&#39;s agent classifies user input to route it optimally:</p><h3 id="classification-logic" tabindex="-1">Classification Logic <a class="header-anchor" href="#classification-logic" aria-label="Permalink to &quot;Classification Logic&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input Pattern</th><th>Classification</th><th>Routing</th></tr></thead><tbody><tr><td>Direct command (e.g., &quot;ls -la&quot;)</td><td>Command</td><td>Terminal view, direct execution</td></tr><tr><td>Question about output</td><td>Query</td><td>Inline agent response in terminal</td></tr><tr><td>Multi-step request</td><td>Complex task</td><td>Conversation view with planning</td></tr><tr><td>Code modification request</td><td>Edit task</td><td>Conversation view with diff preview</td></tr><tr><td>Reference to running process</td><td>FTU interaction</td><td>Terminal view, PTY attachment</td></tr><tr><td>Error in previous block</td><td>Error fix</td><td>Active AI suggestion</td></tr></tbody></table><h3 id="how-classification-works" tabindex="-1">How Classification Works <a class="header-anchor" href="#how-classification-works" aria-label="Permalink to &quot;How Classification Works&quot;">​</a></h3><p>The agent considers:</p><ul><li><strong>Lexical cues</strong>: Imperative verbs (&quot;run&quot;, &quot;execute&quot;) vs. question words (&quot;how&quot;, &quot;why&quot;)</li><li><strong>Context</strong>: Previous blocks, current working directory, running processes</li><li><strong>Complexity estimation</strong>: Single-step vs. multi-step, read vs. write operations</li><li><strong>User preferences</strong>: Configured defaults for ambiguous cases</li><li><strong>Conversation state</strong>: Whether already in a multi-turn conversation</li></ul><h2 id="conversation-management" tabindex="-1">Conversation Management <a class="header-anchor" href="#conversation-management" aria-label="Permalink to &quot;Conversation Management&quot;">​</a></h2><h3 id="forking" tabindex="-1">Forking <a class="header-anchor" href="#forking" aria-label="Permalink to &quot;Forking&quot;">​</a></h3><p>Warp supports conversation branching:</p><ul><li><strong>/fork</strong>: Create a new conversation branch from current point</li><li><strong>/fork-and-compact</strong>: Fork and summarize the parent conversation to save context</li><li><strong>/fork from point</strong>: Fork from a specific earlier point in conversation</li></ul><p>This enables exploratory workflows where the user can try multiple approaches without losing previous context.</p><h3 id="compaction" tabindex="-1">Compaction <a class="header-anchor" href="#compaction" aria-label="Permalink to &quot;Compaction&quot;">​</a></h3><ul><li><strong>/compact</strong>: Summarize conversation history to free context window space</li><li>Preserves key decisions, code changes, and outcomes</li><li>Allows longer-running agent sessions without hitting token limits</li><li>Agent can suggest compaction when context is getting large</li></ul><h3 id="session-persistence" tabindex="-1">Session Persistence <a class="header-anchor" href="#session-persistence" aria-label="Permalink to &quot;Session Persistence&quot;">​</a></h3><ul><li>Conversations persist across Warp restarts</li><li>Stored in Warp Drive for cross-device access</li><li>Can be shared with team members for collaborative debugging</li></ul><h2 id="cloud-agent-loop" tabindex="-1">Cloud Agent Loop <a class="header-anchor" href="#cloud-agent-loop" aria-label="Permalink to &quot;Cloud Agent Loop&quot;">​</a></h2><p>Cloud agents follow a similar loop but with additional orchestration:</p>`,37)),(s(),r(p,null,{default:t(()=>[l(o,{id:"mermaid-540",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20T%5B%22Trigger%3Cbr%2F%3E(Slack%2C%20GitHub%2C%20Linear%2C%20Webhook%2C%20Schedule%2C%20API)%22%5D%20--%3E%20ES%5B%22Environment%20Setup%3Cbr%2F%3E-%20Clone%20repository%3Cbr%2F%3E-%20Start%20Docker%20image%3Cbr%2F%3E-%20Run%20startup%20commands%22%5D%0A%20%20%20%20ES%20--%3E%20EL%5B%22Agent%20Execution%20Loop%3Cbr%2F%3E(same%20as%20local%20agent%20but%20without%20FTU%2FPTY)%3Cbr%2F%3ECommands%2C%20file%20edits%2C%20web%20search%2C%20MCP%20tools%22%5D%0A%20%20%20%20EL%20--%3E%20RR%5B%22Result%20Reporting%3Cbr%2F%3E-%20Post%20to%20Slack%2FLinear%3Cbr%2F%3E-%20Create%20PR%20on%20GitHub%3Cbr%2F%3E-%20Update%20webhook%20caller%3Cbr%2F%3E-%20Session%20available%20in%20web%20app%20for%20review%22%5D%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[a(" Loading... ",-1)])]),_:1})),e[10]||(e[10]=i('<h3 id="key-differences-from-local-loop" tabindex="-1">Key Differences from Local Loop <a class="header-anchor" href="#key-differences-from-local-loop" aria-label="Permalink to &quot;Key Differences from Local Loop&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Local Agent</th><th>Cloud Agent</th></tr></thead><tbody><tr><td>Trigger</td><td>User interaction</td><td>External event</td></tr><tr><td>PTY access</td><td>Full (FTU)</td><td>Simulated terminal</td></tr><tr><td>UI</td><td>Real-time in Warp app</td><td>Web app / Oz CLI</td></tr><tr><td>Parallelism</td><td>Single session</td><td>Multiple parallel sessions</td></tr><tr><td>Environment</td><td>User&#39;s machine</td><td>Configured Docker image</td></tr><tr><td>Human-in-loop</td><td>Real-time takeover</td><td>Async session steering</td></tr><tr><td>Permission</td><td>Interactive prompts</td><td>Pre-configured policy</td></tr></tbody></table><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Warp&#39;s agentic loop is fundamentally shaped by its terminal-native architecture. The ability to read live terminal buffers, write to PTYs, and manage structured blocks gives the agent capabilities that wrapper-based agents cannot replicate. The Oz platform extends this model to cloud execution, creating a unified agent system that spans interactive local development and automated background workflows.</p>',4))])}const w=d(g,[["render",h]]);export{A as __pageData,w as default};
